import software.amazon.awssdk.auth.credentials.ProfileCredentialsProvider
import software.amazon.awssdk.regions.Region
import software.amazon.awssdk.services.s3.S3Client
import software.amazon.awssdk.services.s3.model._

object AWSService {
  def main(args: Array[String]): Unit = {
    val region = Region.US_EAST_1
    val credentialsProvider = ProfileCredentialsProvider.create()
    
    val s3Client = S3Client.builder()
      .region(region)
      .credentialsProvider(credentialsProvider)
      .build()

    // Example operation: List buckets
    listBuckets(s3Client)

    // Close the client when done
    s3Client.close()
  }

  def listBuckets(s3Client: S3Client): Unit = {
    try {
      val response = s3Client.listBuckets()
      println("List of Buckets:")
      response.buckets().forEach(bucket => 
        println(s"Bucket Name: ${bucket.name()}, Creation Date: ${bucket.creationDate()}")
      )
    } catch {
      case e: Exception =>
        println(s"Error listing buckets: ${e.getMessage}")
    }
  }
}